def vowels_count(s):
    vowels = {'a', 'e', 'i', 'o', 'u'}
    count = 0
    lower_s = s.lower()
    for i, char in enumerate(lower_s):
        if char in vowels:
            count += 1
    # Check if the last character is 'y'
    if len(lower_s) > 0 and lower_s[-1] == 'y':
        count += 1
    return count

def pluck(arr):
    if not arr:
        return []
    # Initialize variables to track the smallest even value and its index
    smallest_even = None
    smallest_index = None

    for i, val in enumerate(arr):
        if val % 2 == 0:  # check if the number is even
            if smallest_even is None or val < smallest_even:
                smallest_even = val
                smallest_index = i

    # If no even number found, return an empty list
    if smallest_even is None:
        return []

    return [smallest_even, smallest_index]

