def encode(message):
    vowels = {'a', 'e', 'i', 'o', 'u', 'A', 'E', 'I', 'O', 'U'}
    encoded = []
    for char in message:
        if char in vowels:
            # Determine the new character by moving two places ahead
            new_char = chr(ord(char) + 2)
            # Handle wrapping around for lowercase and uppercase vowels
            if char.islower():
                if new_char > 'z':
                    new_char = chr(ord(new_char) - 26)
            else:
                if new_char > 'Z':
                    new_char = chr(ord(new_char) - 26)
            # Swap the case of the new character
            if char.islower():
                new_char = new_char.upper()
            else:
                new_char = new_char.lower()
            encoded.append(new_char)
        else:
            # Just swap the case if not a vowel
            if char.islower():
                encoded.append(char.upper())
            else:
                encoded.append(char.lower())
    return ''.join(encoded)

