def encode(message):
    # Swap the case of each character
    swapped = message.swapcase()

    # Define mapping for vowels shifted two letters ahead
    shifts = {
       'A': 'C', 'E': 'G', 'I': 'K', 'O': 'Q', 'U': 'W',
       'a': 'c', 'e': 'g', 'i': 'k', 'o': 'q', 'u': 'w'
    }

    # Build the result by applying shifts where needed
    result_chars = []
    for ch in swapped:
        if ch in shifts:
            result_chars.append(shifts[ch])
        else:
            result_chars.append(ch)

    return ''.join(result_chars)

