def get_closest_vowel(word):
    vowels = set("AEIOUaeiou")
    # We only look for vowels that are not at the first or last index
    # and are flanked by consonants on both sides from the right side of the word
    for i in range(len(word) - 2, 0, -1):
        if word[i] in vowels and word[i - 1] not in vowels and word[i + 1] not in vowels:
            return word[i]
    return ""

