def get_closest_vowel(word):
    vowels = "aeiouAEIOU"

    # Start from the end of the word and look for consonants and vowels
    for i in range(len(word) - 2, 0, -1):  # Start from the second last character to the second character
        if word[i] in vowels:  # Check if the character is a vowel
            # Check if there are consonants before and after this vowel
