        balance = 0
        for char in s:
            if char == '(':
                balance += 1
            else:
                balance -= 1
            if balance < 0:
                return False
        return balance == 0

    # Check both possible concatenations
    if is_balanced(s1 + s2):
        return 'Yes'
    if is_balanced(s2 + s1):
        return 'Yes'

    # Also, check if total number of parentheses is balanced
    total = (s1 + s2).count('(') == (s1 + s2).count(')')
    if not total:
        return 'No'

    # Check possible cases where the combined string could be balanced in another way
    # For example, one string has excess opening and the other has excess closing
    # But the total is balanced
    # However, without proper nesting, it's not possible
    # So the initial checks cover the possible valid cases

    return 'No'

