def get_odd_collatz(n):
    collatz_sequence = []
    current = n
    while current != 1:
        collatz_sequence.append(current)
        if current % 2 == 0:
            current = current // 2
        else:
            current = 3 * current + 1
    collatz_sequence.append(1)  # add the final 1
    odd_numbers = [num for num in collatz_sequence if num % 2 != 0]
    odd_numbers_sorted = sorted(list(set(odd_numbers)))  # remove duplicates and sort
    return odd_numbers_sorted

