def get_odd_collatz(n):
    # Generate the Collatz sequence from n down to 1
    sequence = []
    current = n
    while True:
        # If the current number is odd, add it to the sequence
        if current % 2 == 1:
            sequence.append(current)
        if current == 1:
            break
        # Move to the next Collatz term
        if current % 2 == 0:
            current //= 2
        else:
            current = 3 * current + 1

    # Sort the odd numbers and return
    return sorted(sequence)

