def prod_signs(arr):
    if not arr:
        return None
    sum_mag = sum(abs(x) for x in arr)
    has_zero = any(x == 0 for x in arr)
    if has_zero:
        product = 0
    else:
        product = 1
        for x in arr:
            product *= 1 if x > 0 else -1
    return sum_mag * product

def prod_signs(arr):
    if not arr:
        return None

    sign_product = 1
    total_mag = 0

    for num in arr:
        total_mag += abs(num)
        if num == 0:
            sign_product = 0
        elif num < 0 and sign_product != 0:
            sign_product *= -1

    return total_mag * sign_product

