def find_max(words):
    max_unique = -1
    candidates = []
    for word in words:
        unique_chars = len(set(word))
        if unique_chars > max_unique:
            max_unique = unique_chars
            candidates = [word]
        elif unique_chars == max_unique:
            candidates.append(word)
    if not candidates:
        return ""
    candidates.sort()
    return candidates[0]

def find_max(words):
