    answer = None

    for word in words:
        unique_chars_count = len(set(word))
        if unique_chars_count > max_unique_count:
            max_unique_count = unique_chars_count
            answer = word
        elif unique_chars_count == max_unique_count:
            if word < answer:  # lexicographical comparison
                answer = word

    return answer

