class Solution:
    def matrixSum(self, nums: List[List[int]]) -> int:
        # Sort each row in descending order
        for row in nums:
            row.sort(reverse=True)

        # Determine the maximum number of columns (steps needed)
        max_cols = max(len(row) for row in nums)

        total = 0

        # Iterate through each column index up to max_cols
        for j in range(max_cols):
            current_max = 0
            for row in nums:
                if j < len(row):
                    current_max = max(current_max, row[j])
            total += current_max

        return total

class Solution:
    def semiOrderedPermutation(self, nums: List[int]) -> int:
        n = len(nums)
        pos1 = nums.index(1)
        posn = nums.index(n)
        if pos1 < posn:
            return pos1 + (n - 1 - posn)
        else:
            return pos1 + (n - 1 - posn) - 1

class Solution:
    def doesValidArrayExist(self, derived: List[int]) -> bool:
        n = len(derived)
        # Try both possible starting values for original[0]
        for start in [0, 1]:
            original = [start]
            for i in range(n - 1):
                next_bit = original[i] ^ derived[i]
                original.append(next_bit)
            # Check if the last derived condition is satisfied
            if (original[-1] ^ original[0]) == derived[-1]:
                return True
        return False

