        stack = []

        for char in s:
            stack.append(char)
            # Check the last two characters in the stack
            if len(stack) >= 2 and ((stack[-2] == 'A' and stack[-1] == 'B') or (stack[-2] == 'C' and stack[-1] == 'D')):
                # Remove the last two characters if they form "AB" or "CD"
                stack.pop()
                stack.pop()

        return len(stack)

