class Solution:
    def isGood(self, nums: List[int]) -> bool:
        n = max(nums)  # Find the maximum element in the array
        expected_length = n + 1  # The expected length of base[n]

        if len(nums) != expected_length:  # Check if the length matches
            return False

        # Create a frequency dictionary for the numbers in nums
        frequency = {}
        for num in nums:
            if num in frequency:
                frequency[num] += 1
            else:
                frequency[num] = 1

        # Check the frequency of numbers against the expected base[n]
        for i in range(1, n):
            if frequency.get(i, 0) != 1:  # Each number from 1 to n-1 should appear exactly once
                return False

        if frequency.get(n, 0) != 2:  # The number n should appear exactly twice
            return False

        return True

class Solution:
    def isGood(self, nums: List[int]) -> bool:
        n = max(nums)
        if len(nums) != n + 1:
            return False
        if nums.count(n) != 2:
            return False
        remaining = [num for num in nums if num != n]
        remaining.sort()
        expected = list(range(1, n))
        return remaining == expected

