class Solution:
    def numberOfPoints(self, nums: List[List[int]]) -> int:
        if not nums:
            return 0
        # Sort the intervals based on their start points
        sorted_intervals = sorted(nums, key=lambda x: x[0])
        merged = [sorted_intervals[0]]

        for interval in sorted_intervals[1:]:
            last = merged[-1]
            if interval[0] <= last[1]:
                # Merge the intervals
                new_start = last[0]
                new_end = max(last[1], interval[1])
                merged[-1] = [new_start, new_end]
            else:
                merged.append(interval)

        # Calculate the total points covered by merged intervals
        total = 0
        for start, end in merged:
            total += end - start + 1

        return total

