class Solution:
    def shortestBeautifulSubstring(self, s: str, k: int) -> str:
        n = len(s)
        count = 0
        left = 0
        min_len = float('inf')
        start_idx = 0

        for right in range(n):
            if s[right] == '1':
                count += 1

            while count == k:
                if right - left + 1 < min_len:
                    min_len = right - left + 1
                    start_idx = left

                if s[left] == '1':
                    count -= 1
                left += 1

        if min_len == float('inf'):
            return ""
        else:
            return s[start_idx:start_idx+min_len]

