class Solution:
    def findKOr(self, nums: List[int], k: int) -> int:
        # Initialize a list to count the number of elements with each bit set
        bit_count = [0] * 32  # There are 32 bits in an integer

        # Count the number of elements that have each bit set
        for num in nums:
            for i in range(32):
                if num & (1 << i):  # Check if the i-th bit is set
                    bit_count[i] += 1

        # Calculate the K-or based on the bit counts
        k_or = 0
        for i in range(32):
            if bit_count[i] >= k:  # If at least k elements have the i-th bit set
                k_or |= (1 << i)  # Set the i-th bit in the K-or

        return k_or

