class Solution:
    def longestMonotonicSubarray(self, nums: List[int]) -> int:
        if not nums:
            return 0
        max_len = 1
        n = len(nums)
        for i in range(n):
            inc_len = 1
            dec_len = 1
            for j in range(i+1, n):
                if nums[j] > nums[j-1]:
                    inc_len += 1
                else:
                    break
            for j in range(i+1, n):
                if nums[j] < nums[j-1]:
                    dec_len += 1
                else:
                    break
            current_max = max(inc_len, dec_len)
            if current_max > max_len:
                max_len = current_max
        return max_len

