        max_len = 1
        n = len(nums)
        for i in range(n):
            inc_len = 1
            dec_len = 1
            for j in range(i+1, n):
                if nums[j] > nums[j-1]:
                    inc_len += 1
                else:
                    break
            for j in range(i+1, n):
                if nums[j] < nums[j-1]:
                    dec_len += 1
                else:
                    break
            current_max = max(inc_len, dec_len)
            if current_max > max_len:
                max_len = current_max
        return max_len

class Solution:
    def longestMonotonicSubarray(self, nums: List[int]) -> int:
        n = len(nums)
        if n == 0:
            return 0
        inc = [1] * n
        dec = [1] * n

        for i in range(1, n):
            if nums[i] > nums[i-1]:
                inc[i] = inc[i-1] + 1
            elif nums[i] < nums[i-1]:
                dec[i] = dec[i-1] + 1

        return max(max(inc), max(dec))

class Solution:
    def numberOfRightTriangles(self, grid: List[List[int]]) -> int:
        rows = len(grid)
        if rows == 0:
            return 0
        cols = len(grid[0])
        # Compute row sums
        row_counts = [sum(row) for row in grid]
        # Compute column sums
        col_counts = [0] * cols
        for j in range(cols):
            for i in range(rows):
                col_counts[j] += grid[i][j]
        # Calculate total right triangles
        total = 0
        for i in range(rows):
            for j in range(cols):
                if grid[i][j]:
                    total += (row_counts[i] - 1) * (col_counts[j] - 1)
        return total

class Solution:
    def numberOfRightTriangles(self, grid: List[List[int]]) -> int:
        rows = len(grid)
        cols = len(grid[0]) if rows > 0 else 0

        # Precompute the number of 1s in each row and column
        row_counts = [0] * rows
        col_counts = [0] * cols

        for i in range(rows):
            for j in range(cols):
                if grid[i][j] == 1:
                    row_counts[i] += 1
                    col_counts[j] += 1

        total = 0

        # Iterate through each cell to find the number of right triangles where it is the right angle
        for i in range(rows):
            for j in range(cols):
                if grid[i][j] == 1:
                    # The number of right triangles with (i,j) as the right angle is (row_counts[i] - 1) * (col_counts[j] - 1)
                    total += (row_counts[i] - 1) * (col_counts[j] - 1)

        return total

