class Solution:
    def minChanges(self, n: int, k: int) -> int:
        if n == k:
            return 0
        if n < k:
            return -1
        # Check if all set bits in k are also set in n
        if (n & k) != k:
            return -1
        # Count the number of set bits in n that are not in k
        diff = n ^ k
        # Count the number of set bits in diff that are set in n
        count = 0
        while diff:
            if diff & 1:
                if n & 1:
                    count += 1
                else:
                    return -1
            diff >>= 1
            n >>= 1
        return count

