class Solution:
    def countSymmetricIntegers(self, low: int, high: int) -> int:
        def is_symmetric(num):
            num_str = str(num)
            n = len(num_str) // 2
            return sum(map(int, num_str[:n])) == sum(map(int, num_str[n:]))

        count = 0
        for num in range(low, high+1):
            if len(str(num)) % 2 == 0 and is_symmetric(num):
                count += 1

        return count

