        n = len(grid)
        champion = 0

        for i in range(1, n):
            if grid[champion][i] == 1:
                # champion is stronger than i, keep champion
                continue
            else:
                # i is stronger than champion, update champion
                champion = i

        return champion

class Solution:
    def beautifulSubstrings(self, s: str, k: int) -> int:
        vowels = {'a', 'e', 'i', 'o', 'u'}
        n = len(s)
        count = 0
        for i in range(n):
            vowel_count = 0
            consonant_count = 0
            for j in range(i, n):
                if s[j] in vowels:
                    vowel_count += 1
                else:
                    consonant_count += 1
                if vowel_count == consonant_count and (vowel_count * consonant_count) % k == 0:
                    count += 1
        return count

class Solution:
    def findMissingAndRepeatedValues(self, grid: List[List[int]]) -> List[int]:
        n = len(grid)
        total_numbers = n * n
        count = {}

        # Flatten the grid and count occurrences
        for row in grid:
            for num in row:
                if num in count:
                    count[num] += 1
                else:
                    count[num] = 1

        # Find the repeating number
        a = None
        for num in count:
            if count[num] == 2:
                a = num
                break

        # Find the missing number
        b = None
        for num in range(1, total_numbers + 1):
            if num not in count:
                b = num
                break

        return [a, b]

class Solution:
