class Solution:
    def longestMonotonicSubarray(self, nums: List[int]) -> int:
        n = len(nums)
        if n == 0:
            return 0
        inc = [1] * n
        dec = [1] * n

        for i in range(1, n):
            if nums[i] > nums[i-1]:
                inc[i] = inc[i-1] + 1
            elif nums[i] < nums[i-1]:
                dec[i] = dec[i-1] + 1

        return max(max(inc), max(dec))

class Solution:
    def numberOfRightTriangles(self, grid: List[List[int]]) -> int:
        rows = len(grid)
        if rows == 0:
            return 0
        cols = len(grid[0])
        # Compute row sums
        row_counts = [sum(row) for row in grid]
        # Compute column sums
        col_counts = [0] * cols
        for j in range(cols):
            for i in range(rows):
                col_counts[j] += grid[i][j]
        # Calculate total right triangles
        total = 0
        for i in range(rows):
            for j in range(cols):
                if grid[i][j]:
                    total += (row_counts[i] - 1) * (col_counts[j] - 1)
        return total

class Solution:
    def numberOfRightTriangles(self, grid: List[List[int]]) -> int:
        rows = len(grid)
        cols = len(grid[0]) if rows > 0 else 0

        # Precompute the number of 1s in each row and column
        row_counts = [0] * rows
        col_counts = [0] * cols

        for i in range(rows):
            for j in range(cols):
                if grid[i][j] == 1:
                    row_counts[i] += 1
                    col_counts[j] += 1

        total = 0

        # Iterate through each cell to find the number of right triangles where it is the right angle
        for i in range(rows):
            for j in range(cols):
                if grid[i][j] == 1:
                    # The number of right triangles with (i,j) as the right angle is (row_counts[i] - 1) * (col_counts[j] - 1)
                    total += (row_counts[i] - 1) * (col_counts[j] - 1)

        return total

class Solution:
    def valueAfterKSeconds(self, n: int, k: int) -> int:
        MOD = 10**9 + 7
        dp = [1] * n
        for _ in range(k):
            new_dp = [0] * n
            new_dp[0] = dp[0]
            for i in range(1, n):
                new_dp[i] = (new_dp[i-1] + dp[i]) % MOD
            dp = new_dp
        return dp[-1]

