class Solution:
    def stringHash(self, s: str, k: int) -> str:
        result = []
        n = len(s)
        for i in range(0, n, k):
            substring = s[i:i+k]
            total = 0
            for c in substring:
                total += ord(c) - ord('a')
            mod = total % 26
            result.append(chr(mod + ord('a')))
        return ''.join(result)

class Solution:
    def countKConstraintSubstrings(self, s: str, k: int) -> int:
        n = len(s)
        count = 0

        for i in range(n):
            zeros = 0
            ones = 0
            for j in range(i, n):
                if s[j] == '0':
                    zeros += 1
                else:
                    ones += 1

                if zeros <= k or ones <= k:
                    count += 1
                else:
                    break

        return count

class Solution:
    def kthCharacter(self, k: int) -> str:
        word = "a"
        while len(word) < k:
            new_part = ''.join(chr((ord(c) - ord('a') + 1) % 26 + ord('a')) for c in word)
            word += new_part
        return word[k-1]

class Solution:
    def smallestNumber(self, n: int, t: int) -> int:
        def digit_product(num):
            product = 1
            while num > 0:
                product *= num % 10
                num //= 10
            return product

        while True:
            if digit_product(n) % t == 0:
                return n
            n += 1
